mapper.select:
select t.*, v.file_name as video_name
from video_detection_task t
left join video v on t.video_id = v.id
where t.video_id = #{videoId}
order by t.create_time desc
limit #{page}, #{size}

mapper.update:
update video_detection_task set status = #{status}

    , start_time = now()


    , end_time = now()

where id = #{id}
